INSERT INTO follow_up_shift_plan (
    department_id, month, status, ai_generated, ai_summary, created_by
) VALUES (
    #{departmentId}, #{month},
    COALESCE(#{status}, 'draft'),
    COALESCE(#{aiGenerated}, FALSE),
    #{aiSummary}, #{createdBy}
)

mapper.select:
SELECT s.id AS "id", s.plan_id AS "planId", s.employee_id AS "employeeId", e.realname AS "employeeName", s.department_id AS "departmentId", s.work_date AS "workDate", s.shift_type AS "shiftType", s.status AS "status" FROM follow_up_staff_shift s LEFT JOIN employee e ON e.id = s.employee_id
AND s.employee_id = #{employeeId} AND s.department_id = #{departmentId} AND s.work_date >= #{from} AND s.work_date <= #{to}
ORDER BY s.work_date ASC, s.id ASC

SELECT id AS "id", employee_id AS "employeeId", work_date AS "workDate", status AS "status"
FROM follow_up_staff_shift
WHERE employee_id = #{employeeId}
  AND work_date = #{workDate}
  AND status != 'cancelled'
LIMIT 1

mapper.update:
UPDATE follow_up_staff_shift
SET work_date = #{workDate}
WHERE id = #{shiftId}

mapper.select:
SELECT r.id AS "id", r.employee_id AS "employeeId", e.realname AS "employeeName", r.department_id AS "departmentId", r.original_shift_id AS "originalShiftId", s.work_date AS "originalWorkDate", r.requested_work_date AS "requestedWorkDate", r.reason AS "reason", r.status AS "status", r.created_at AS "createdAt" FROM follow_up_shift_change_request r LEFT JOIN employee e ON e.id = r.employee_id LEFT JOIN follow_up_staff_shift s ON s.id = r.original_shift_id WHERE r.status = 'pending'
AND r.department_id = #{departmentId}
ORDER BY r.created_at ASC

